fn grammar_is_auto_detected_from_file_extension_example_1() {
    let mut world = World::new();
    let mut example: HashMap<String, String> = HashMap::new();
    example.insert("ext".to_string(), "tsx".to_string());
    example.insert("left_file".to_string(), "src/alpha.tsx".to_string());
    example.insert("right_file".to_string(), "src/beta.tsx".to_string());
    example.insert("structure".to_string(), "accumulate_sum".to_string());
    example.insert("left_ids".to_string(), "a,b,sum".to_string());
    example.insert("right_ids".to_string(), "x,y,total".to_string());
    example.insert("args".to_string(), "./src".to_string());
    example.insert("exit_code".to_string(), "1".to_string());

    let result = steps::dispatch(
        "a \"<ext>\" file \"<left_file>\" containing a function with structure \"<structure>\" and identifiers \"<left_ids>\"",
        &mut world,
        &example,
    );
    assert!(
        result.success,
        "step failed [a \"<ext>\" file \"<left_file>\" containing a function with structure \"<structure>\" and identifiers \"<left_ids>\"]: {}",
        result.message
    );
    let result = steps::dispatch(
        "a \"<ext>\" file \"<right_file>\" containing a function with structure \"<structure>\" and identifiers \"<right_ids>\"",
        &mut world,
        &example,
    );
    assert!(
        result.success,
        "step failed [a \"<ext>\" file \"<right_file>\" containing a function with structure \"<structure>\" and identifiers \"<right_ids>\"]: {}",
        result.message
    );
    let result = steps::dispatch(
        "I run drywall with the arguments \"<args>\"",
        &mut world,
        &example,
    );
    assert!(
        result.success,
        "step failed [I run drywall with the arguments \"<args>\"]: {}",
        result.message
    );
    let result = steps::dispatch("the exit code is \"<exit_code>\"", &mut world, &example);
    assert!(
        result.success,
        "step failed [the exit code is \"<exit_code>\"]: {}",
        result.message
    );
    let result = steps::dispatch(
        "stdout reports a duplicate pair for \"<left_file>\" and \"<right_file>\"",
        &mut world,
        &example,
    );
    assert!(
        result.success,
        "step failed [stdout reports a duplicate pair for \"<left_file>\" and \"<right_file>\"]: {}",
        result.message
    );
}

