    };
    format!(
        "const {fn_name} = ({p0}, {p1}) => {{\n  let {p2} = {p0} + {p1};\n  let extra = {p2} * 2;\n  let more = extra + {p0};\n  let result = more + {p1};\n  return result;\n}};\n"
    )
}

